#include<iostream>#include<vector>#include<algorithm>#define ll long longusing namespace std;int main(){    ios_base::sync_with_stdio(false);    cin.tie(NULL);    int M= 1e9 + 7;    int t;    cin>>t;    while(t--){        ll n;        cin>>n;        vector<ll> a(n);                for(int i=0;i<n;i++){            cin>>a[i];                   }        vector<ll>b(n);        for(int i=0;i<n;i++){            cin>>b[i];        }        sort(a.begin(),a.end());        sort(b.rbegin(),b.rend());        ll ans=1;        for(int i=0;i<n;i++){            ll temp= upper_bound(a.begin(),a.end(),b[i])-a.begin();            ll cnt= n- temp;            ans=ans *  max(0LL,cnt-i) % M;         }        cout<<ans<<"\n";    }}